BASE = os.path.expanduser("~/swarm-platform/federation")
os.makedirs(BASE, exist_ok=True)
built = 0
skipped = 0

for d in DOMAINS:
    path = os.path.join(BASE, d["domain"])
    if os.path.exists(path):
        print(f"  skip  {d['domain']}")
        skipped += 1
        continue
    os.makedirs(os.path.join(path, "frontend"), exist_ok=True)
    os.makedirs(os.path.join(path, "backend"), exist_ok=True)
    champion = {"domain":d["domain"],"name":d["name"],"score":0,"generation":0,"node":uuid.uuid4().hex[:8],"shared_at":datetime.now().isoformat(),"tagline":d["tagline"],"color":d["color"],"user":d["user"],"worst_moment":d["worst_moment"],"today_focus":d["today_focus"],"human_greeting":d["human_greeting"],"features":d["features"],"wisdom":d["wisdom"],"wisdom_scores":{"wu_wei_flow":True,"offline_first":True,"today_focus":True,"domain_color":True,"no_login_wall":True,"human_greeting":True}}
    with open(os.path.join(path,"node_champion.json"),"w") as f: json.dump(champion,f,indent=2)
    html = f"""<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>{d['name']}</title><style>:root{{--c:{d['color']}}}*{{box-sizing:border-box;margin:0;padding:0}}body{{font-family:-apple-system,sans-serif;background:#f8f9fa;color:#222}}.hdr{{background:var(--c);color:#fff;padding:24px 20px}}.greet{{font-size:18px;opacity:.9;margin-bottom:6px}}.name{{font-size:28px;font-weight:700}}.tag{{font-size:13px;opacity:.8;margin-top:4px}}.card{{background:#fff;margin:16px;padding:20px;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.08);border-left:4px solid var(--c)}}.lbl{{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#888;margin-bottom:8px}}.focus{{font-size:18px;font-weight:600}}.chips{{margin:0 16px;display:flex;flex-wrap:wrap;gap:8px}}.chip{{background:#fff;border:1px solid #e0e0e0;border-radius:20px;padding:6px 14px;font-size:13px}}.wisdom{{margin:16px;padding:16px;background:var(--c);border-radius:12px;color:#fff;font-style:italic;font-size:14px}}.btn{{display:block;margin:16px;padding:16px;background:var(--c);color:#fff;border:none;border-radius:12px;font-size:17px;font-weight:600;width:calc(100% - 32px);cursor:pointer}}.off{{text-align:center;font-size:12px;color:#888;padding:8px}}</style></head><body><div class="hdr"><div class="greet">{d['human_greeting']}</div><div class="name">{d['name']}</div><div class="tag">{d['tagline']}</div></div><div class="card"><div class="lbl">Today's Focus</div><div class="focus">{d['today_focus']}</div></div><div class="chips">{"".join(f'<div class="chip">{f.replace("_"," ").title()}</div>' for f in d['features'])}</div><div class="wisdom">"{d['wisdom']}"</div><button class="btn">Get Started</button><div class="off">Works offline — no account needed</div></body></html>"""
    with open(os.path.join(path,"frontend","index.html"),"w") as f: f.write(html)
    backend = "from flask import Flask,jsonify\nfrom flask_cors import CORS\napp=Flask(__name__)\nCORS(app)\n@app.route('/')\ndef index():return jsonify({'domain':'"+d['domain']+"','name':'"+d['name']+"','greeting':'"+d['human_greeting']+"'})\n@app.route('/health')\ndef health():return jsonify({'status':'ok'})\nif __name__=='__main__':app.run(host='0.0.0.0',port=5000)\n"
    with open(os.path.join(path,"backend","app.py"),"w") as f: f.write(backend)
    with open(os.path.join(path,"backend","requirements.txt"),"w") as f: f.write("flask\nflask-cors\n")
    print(f"  built {d['domain']:35s} {d['name']}")
    built += 1

registry = {"generated_at":datetime.now().isoformat(),"built":built,"skipped":skipped,"total_domains":len(DOMAINS),"domains":[{"domain":d["domain"],"name":d["name"],"tagline":d["tagline"]} for d in DOMAINS]}
